5	#[tokio::main(flavor = "multi_thread")]
6	async fn main() -> Result<(), Box<dyn std::error::Error>> {
7	    let mut bind_addr = String::from("127.0.0.1:0");
8	    let mut args = env::args().skip(1);
9	    while let Some(arg) = args.next() {
10	        match arg.as_str() {
11	            "--bind" => {
12	                bind_addr = args
13	                    .next()
14	                    .ok_or_else(|| "missing value for --bind".to_string())?;
15	            }
16	            flag if flag.starts_with("--bind=") => {
17	                bind_addr = flag[7..].to_string();
18	            }
19	            "--help" | "-h" => {
20	                println!("Usage: mock-anthropic-service [--bind HOST:PORT]");
21	                return Ok(());
22	            }
23	            other => {
24	                return Err(format!("unsupported argument: {other}").into());
25	            }
26	        }
27	    }
28	
29	    let server = MockAnthropicService::spawn_on(&bind_addr).await?;
30	    println!("MOCK_ANTHROPIC_BASE_URL={}", server.base_url());
31	    tokio::signal::ctrl_c().await?;
32	    drop(server);
33	    Ok(())
34	}
