38	    pub async fn spawn_on(bind_addr: &str) -> io::Result<Self> {
39	        let listener = TcpListener::bind(bind_addr).await?;
40	        let address = listener.local_addr()?;
41	        let requests = Arc::new(Mutex::new(Vec::new()));
42	        let (shutdown_tx, mut shutdown_rx) = oneshot::channel();
43	        let request_state = Arc::clone(&requests);
44	
45	        let join_handle = tokio::spawn(async move {
46	            loop {
47	                tokio::select! {
48	                    _ = &mut shutdown_rx => break,
49	                    accepted = listener.accept() => {
50	                        let Ok((socket, _)) = accepted else {
51	                            break;
52	                        };
53	                        let request_state = Arc::clone(&request_state);
54	                        tokio::spawn(async move {
55	                            let _ = handle_connection(socket, request_state).await;
56	                        });
57	                    }
58	                }
59	            }
60	        });
61	
62	        Ok(Self {
63	            base_url: format!("http://{address}"),
64	            requests,
65	            shutdown: Some(shutdown_tx),
66	            join_handle,
67	        })
68	    }
69	
70	    #[must_use]
71	    pub fn base_url(&self) -> String {
72	        self.base_url.clone()
73	    }
74	
75	    pub async fn captured_requests(&self) -> Vec<CapturedRequest> {
76	        self.requests.lock().await.clone()
77	    }
78	}
