142	async fn handle_connection(
143	    mut socket: tokio::net::TcpStream,
144	    requests: Arc<Mutex<Vec<CapturedRequest>>>,
145	) -> io::Result<()> {
146	    let (method, path, headers, raw_body) = read_http_request(&mut socket).await?;
147	    let request: MessageRequest = serde_json::from_str(&raw_body)
148	        .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error.to_string()))?;
149	    let scenario = detect_scenario(&request)
150	        .ok_or_else(|| io::Error::new(io::ErrorKind::InvalidInput, "missing parity scenario"))?;
151	
152	    requests.lock().await.push(CapturedRequest {
153	        method,
154	        path,
155	        headers,
156	        scenario: scenario.name().to_string(),
157	        stream: request.stream,
158	        raw_body,
159	    });
160	
161	    let response = build_http_response(&request, scenario);
162	    socket.write_all(response.as_bytes()).await?;
163	    Ok(())
164	}
