166	async fn read_http_request(
167	    socket: &mut tokio::net::TcpStream,
168	) -> io::Result<(String, String, HashMap<String, String>, String)> {
169	    let mut buffer = Vec::new();
170	    let mut header_end = None;
171	
172	    loop {
173	        let mut chunk = [0_u8; 1024];
174	        let read = socket.read(&mut chunk).await?;
175	        if read == 0 {
176	            break;
177	        }
178	        buffer.extend_from_slice(&chunk[..read]);
179	        if let Some(position) = find_header_end(&buffer) {
180	            header_end = Some(position);
181	            break;
182	        }
183	    }
184	
185	    let header_end = header_end
186	        .ok_or_else(|| io::Error::new(io::ErrorKind::UnexpectedEof, "missing http headers"))?;
187	    let (header_bytes, remaining) = buffer.split_at(header_end);
188	    let header_text = String::from_utf8(header_bytes.to_vec())
189	        .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error.to_string()))?;
190	    let mut lines = header_text.split("\r\n");
191	    let request_line = lines
192	        .next()
193	        .ok_or_else(|| io::Error::new(io::ErrorKind::InvalidData, "missing request line"))?;
194	    let mut request_parts = request_line.split_whitespace();
195	    let method = request_parts
196	        .next()
197	        .ok_or_else(|| io::Error::new(io::ErrorKind::InvalidData, "missing method"))?
198	        .to_string();
199	    let path = request_parts
200	        .next()
201	        .ok_or_else(|| io::Error::new(io::ErrorKind::InvalidData, "missing path"))?
202	        .to_string();
203	
204	    let mut headers = HashMap::new();
205	    let mut content_length = 0_usize;
206	    for line in lines {
207	        if line.is_empty() {
208	            continue;
209	        }
210	        let (name, value) = line.split_once(':').ok_or_else(|| {
211	            io::Error::new(io::ErrorKind::InvalidData, "malformed http header line")
212	        })?;
213	        let value = value.trim().to_string();
214	        if name.eq_ignore_ascii_case("content-length") {
215	            content_length = value.parse().map_err(|error| {
216	                io::Error::new(
217	                    io::ErrorKind::InvalidData,
218	                    format!("invalid content-length: {error}"),
219	                )
220	            })?;
221	        }
222	        headers.insert(name.to_ascii_lowercase(), value);
223	    }
224	
225	    let mut body = remaining[4..].to_vec();
226	    while body.len() < content_length {
227	        let mut chunk = vec![0_u8; content_length - body.len()];
228	        let read = socket.read(&mut chunk).await?;
229	        if read == 0 {
230	            break;
231	        }
232	        body.extend_from_slice(&chunk[..read]);
233	    }
234	
235	    let body = String::from_utf8(body)
236	        .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error.to_string()))?;
237	    Ok((method, path, headers, body))
238	}
