244	fn detect_scenario(request: &MessageRequest) -> Option<Scenario> {
245	    request.messages.iter().rev().find_map(|message| {
246	        message.content.iter().rev().find_map(|block| match block {
247	            InputContentBlock::Text { text } => text
248	                .split_whitespace()
249	                .find_map(|token| token.strip_prefix(SCENARIO_PREFIX))
250	                .and_then(Scenario::parse),
251	            _ => None,
252	        })
253	    })
254	}
