256	fn latest_tool_result(request: &MessageRequest) -> Option<(String, bool)> {
257	    request.messages.iter().rev().find_map(|message| {
258	        message.content.iter().rev().find_map(|block| match block {
259	            InputContentBlock::ToolResult {
260	                content, is_error, ..
261	            } => Some((flatten_tool_result_content(content), *is_error)),
262	            _ => None,
263	        })
264	    })
265	}
