267	fn tool_results_by_name(request: &MessageRequest) -> HashMap<String, (String, bool)> {
268	    let mut tool_names_by_id = HashMap::new();
269	    for message in &request.messages {
270	        for block in &message.content {
271	            if let InputContentBlock::ToolUse { id, name, .. } = block {
272	                tool_names_by_id.insert(id.clone(), name.clone());
273	            }
274	        }
275	    }
276	
277	    let mut results = HashMap::new();
278	    for message in request.messages.iter().rev() {
279	        for block in message.content.iter().rev() {
280	            if let InputContentBlock::ToolResult {
281	                tool_use_id,
282	                content,
283	                is_error,
284	            } = block
285	            {
286	                let tool_name = tool_names_by_id
287	                    .get(tool_use_id)
288	                    .cloned()
289	                    .unwrap_or_else(|| tool_use_id.clone());
290	                results
291	                    .entry(tool_name)
292	                    .or_insert_with(|| (flatten_tool_result_content(content), *is_error));
293	            }
294	        }
295	    }
296	    results
297	}
